function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return fallback;
  try { return JSON.parse(value); } catch { return fallback; }
}

const payload = parseMaybeJson($json.payload, {});
return [{
  ...payload,
  notes: [
    ...(payload.notes || []),
    "subworkflowschedule_followupinput_normalized"
  ]
}];

return [{
  ...$json,
  db_operations: ["followups"],
  followup: {
    type: $json.execution_context.followup_type,
    scheduled_for: $json.execution_context.scheduled_for
  },
  state_update: {
    ...$json.execution_context.state_update,
    last_bot_action: "schedule_followup"
  }
}];

